const input = $('Execute Workflow Trigger').first().json || {};

const normalizeString = (value) => {
  if (value === null || value === undefined) return '';
  return String(value).trim();
};

const HUBSPOT_INDUSTRIES = new Set(['ACCOUNTING','AIRLINES_AVIATION','ALTERNATIVE_DISPUTE_RESOLUTION','ALTERNATIVE_MEDICINE','ANIMATION','APPAREL_FASHION','ARCHITECTURE_PLANNING','ARTS_AND_CRAFTS','AUTOMOTIVE','AVIATION_AEROSPACE','BANKING','BIOTECHNOLOGY','BROADCAST_MEDIA','BUILDING_MATERIALS','BUSINESS_SUPPLIES_AND_EQUIPMENT','CAPITAL_MARKETS','CHEMICALS','CIVIC_SOCIAL_ORGANIZATION','CIVIL_ENGINEERING','COMMERCIAL_REAL_ESTATE','COMPUTER_NETWORK_SECURITY','COMPUTER_GAMES','COMPUTER_HARDWARE','COMPUTER_NETWORKING','COMPUTER_SOFTWARE','INTERNET','CONSTRUCTION','CONSUMER_ELECTRONICS','CONSUMER_GOODS','CONSUMER_SERVICES','COSMETICS','DAIRY','DEFENSE_SPACE','DESIGN','EDUCATION_MANAGEMENT','E_LEARNING','ELECTRICAL_ELECTRONIC_MANUFACTURING','ENTERTAINMENT','ENVIRONMENTAL_SERVICES','EVENTS_SERVICES','EXECUTIVE_OFFICE','FACILITIES_SERVICES','FARMING','FINANCIAL_SERVICES','FINE_ART','FISHERY','FOOD_BEVERAGES','FOOD_PRODUCTION','FUND_RAISING','FURNITURE','GAMBLING_CASINOS','GLASS_CERAMICS_CONCRETE','GOVERNMENT_ADMINISTRATION','GOVERNMENT_RELATIONS','GRAPHIC_DESIGN','HEALTH_WELLNESS_AND_FITNESS','HIGHER_EDUCATION','HOSPITAL_HEALTH_CARE','HOSPITALITY','HUMAN_RESOURCES','IMPORT_AND_EXPORT','INDIVIDUAL_FAMILY_SERVICES','INDUSTRIAL_AUTOMATION','INFORMATION_SERVICES','INFORMATION_TECHNOLOGY_AND_SERVICES','INSURANCE','INTERNATIONAL_AFFAIRS','INTERNATIONAL_TRADE_AND_DEVELOPMENT','INVESTMENT_BANKING','INVESTMENT_MANAGEMENT','JUDICIARY','LAW_ENFORCEMENT','LAW_PRACTICE','LEGAL_SERVICES','LEGISLATIVE_OFFICE','LEISURE_TRAVEL_TOURISM','LIBRARIES','LOGISTICS_AND_SUPPLY_CHAIN','LUXURY_GOODS_JEWELRY','MACHINERY','MANAGEMENT_CONSULTING','MARITIME','MARKET_RESEARCH','MARKETING_AND_ADVERTISING','MECHANICAL_OR_INDUSTRIAL_ENGINEERING','MEDIA_PRODUCTION','MEDICAL_DEVICES','MEDICAL_PRACTICE','MENTAL_HEALTH_CARE','MILITARY','MINING_METALS','MOTION_PICTURES_AND_FILM','MUSEUMS_AND_INSTITUTIONS','MUSIC','NANOTECHNOLOGY','NEWSPAPERS','NON_PROFIT_ORGANIZATION_MANAGEMENT','OIL_ENERGY','ONLINE_MEDIA','OUTSOURCING_OFFSHORING','PACKAGE_FREIGHT_DELIVERY','PACKAGING_AND_CONTAINERS','PAPER_FOREST_PRODUCTS','PERFORMING_ARTS','PHARMACEUTICALS','PHILANTHROPY','PHOTOGRAPHY','PLASTICS','POLITICAL_ORGANIZATION','PRIMARY_SECONDARY_EDUCATION','PRINTING','PROFESSIONAL_TRAINING_COACHING','PROGRAM_DEVELOPMENT','PUBLIC_POLICY','PUBLIC_RELATIONS_AND_COMMUNICATIONS','PUBLIC_SAFETY','PUBLISHING','RAILROAD_MANUFACTURE','RANCHING','REAL_ESTATE','RECREATIONAL_FACILITIES_AND_SERVICES','RELIGIOUS_INSTITUTIONS','RENEWABLES_ENVIRONMENT','RESEARCH','RESTAURANTS','RETAIL','SECURITY_AND_INVESTIGATIONS','SEMICONDUCTORS','SHIPBUILDING','SPORTING_GOODS','SPORTS','STAFFING_AND_RECRUITING','SUPERMARKETS','TELECOMMUNICATIONS','TEXTILES','THINK_TANKS','TOBACCO','TRANSLATION_AND_LOCALIZATION','TRANSPORTATION_TRUCKING_RAILROAD','UTILITIES','VENTURE_CAPITAL_PRIVATE_EQUITY','VETERINARY','WAREHOUSING','WHOLESALE','WINE_AND_SPIRITS','WIRELESS','WRITING_AND_EDITING','MOBILE_GAMES']);
const INDUSTRY_MAP = { 'HVAC':'MECHANICAL_OR_INDUSTRIAL_ENGINEERING', 'HVAC COMPANY':'MECHANICAL_OR_INDUSTRIAL_ENGINEERING', 'PLUMBING':'CONSTRUCTION', 'ELECTRICAL':'ELECTRICAL_ELECTRONIC_MANUFACTURING', 'ROOFING':'CONSTRUCTION', 'GENERAL CONTRACTOR':'CONSTRUCTION' };
function toHubSpotIndustry(raw) {
  const s = normalizeString(raw);
  if (!s) return '';
  const upper = s.toUpperCase();
  return INDUSTRY_MAP[upper] || (HUBSPOT_INDUSTRIES.has(upper) ? upper : 'MECHANICAL_OR_INDUSTRIAL_ENGINEERING');
}

const customProps = input.customProps && typeof input.customProps === 'object' && !Array.isArray(input.customProps)
  ? input.customProps
  : {};

const rawIndustry = normalizeString(input.industry);
const industry = rawIndustry ? toHubSpotIndustry(input.industry) : '';

const baseProperties = {
  email: normalizeString(input.email),
  phone: normalizeString(input.phone),
  firstname: normalizeString(input.firstName),
  lastname: normalizeString(input.lastName),
  company: normalizeString(input.company)
};
if (industry) baseProperties.industry = industry;
// lead_source and lead_score are custom in HubSpot - not sent by default; create them in HubSpot and pass via customProps if needed


const properties = {};
for (const [key, value] of Object.entries({ ...baseProperties, ...customProps })) {
  if (!key) continue;
  if (value === null || value === undefined) continue;

  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (trimmed) properties[key] = trimmed;
    continue;
  }

  if (typeof value === 'number') {
    if (Number.isFinite(value)) properties[key] = String(value);
    continue;
  }

  if (typeof value === 'boolean') {
    properties[key] = value ? 'true' : 'false';
    continue;
  }
}

// HubSpot rejects placeholder/synthetic emails (e.g. ...@leads.intraweb.local)
const isPlaceholderOrInvalidEmail = (e) => {
  const s = (e || '').trim();
  if (!s) return true;
  if (s.toLowerCase().indexOf('@leads.intraweb.local') !== -1) return true;
  return !/^[^@]+@[^@]+\.[a-z]{2,}$/i.test(s);
};
const hasValidEmail = !isPlaceholderOrInvalidEmail(properties.email);
if (!hasValidEmail) delete properties.email;

const toCanonicalPhone = (raw) => {
  const d = String(raw || '').replace(/\D/g, '');
  if (d.length < 10) return '';
  if (d.length === 10) return '+1' + d;
  if (d.length === 11 && d.startsWith('1')) return '+' + d;
  return '+' + d;
};
const canonicalPhone = toCanonicalPhone(normalizeString(input.phone));
if (canonicalPhone) {
  properties.phone = canonicalPhone;
} else {
  delete properties.phone;
}
const hasNormalizedPhone = Boolean(canonicalPhone);

return [{
  json: {
    email: properties.email || '',
    phone: canonicalPhone,
    canonicalPhone,
    properties,
    hasValidEmail: hasValidEmail,
    hasValidEmailStr: hasValidEmail ? 'true' : 'false',
    hasNormalizedPhone,
    hasNormalizedPhoneStr: hasNormalizedPhone ? 'true' : 'false'
  }
}];

const searchResult = $('Search by Email').first().json;
const contactId = searchResult.results[0].id;

return [{ json: { contactId: contactId, action: 'update_existing' } }];

const searchResult = $('Search by Phone').first().json;
const contactId = searchResult.results[0].id;

return [{ json: { contactId: contactId, action: 'update_existing' } }];

// Input = output of Update Contact or Create Contact. HubSpot uses vid. Return plain object only.
const item = $input.first();
const raw = item && item.json && typeof item.json === 'object' ? item.json : {};
const contactId = raw.vid ?? raw.id ?? raw.contactId;
const id = contactId != null ? String(contactId) : null;
let action = 'unknown';
try {
  if ($('Update Contact').all().length > 0) action = 'updated';
} catch (e) {}
try {
  if (action === 'unknown' && $('Create Contact').all().length > 0) action = 'created';
} catch (e2) {}
return [{
  json: {
    success: true,
    data: { contactId: id, action: String(action) },
    error: null
  }
}];
